import { useState } from "react";
import { useData } from "../contexts/DataContext";
import { useAuth } from "../contexts/AuthContext";
import { Button } from "../components/ui/button";
import { Input } from "../components/ui/input";
import { Label } from "../components/ui/label";
import { Save, LogOut } from "lucide-react";
import { toast } from "sonner";
import { useNavigate } from "react-router-dom";

export default function Profil() {
  const { profile, setProfile } = useData();
  const { logout } = useAuth();
  const navigate = useNavigate();
  const [form, setForm] = useState(profile);
  const set = (k, v) => setForm({ ...form, [k]: v });

  const handleSave = () => {
    setProfile(form);
    toast.success("Profil berhasil diperbarui");
  };

  const handleLogout = () => {
    logout();
    navigate("/login");
  };

  return (
    <div className="max-w-[900px]" data-testid="profil-page">
      <h1 className="text-3xl font-extrabold text-gray-900">Profil</h1>
      <p className="text-sm text-gray-500 mt-1 mb-8">Kelola informasi akun Anda</p>

      <div className="mpl-card p-7">
        <div className="flex items-center gap-5 pb-7 border-b border-gray-100">
          <div className="w-20 h-20 rounded-2xl bg-[#F59E0B] text-white flex items-center justify-center text-3xl font-extrabold">
            {form.name?.[0] || "Z"}
          </div>
          <div>
            <div className="text-xl font-bold text-gray-900">{form.name}</div>
            <div className="text-[11px] tracking-wider uppercase text-gray-400 font-semibold">{form.role}</div>
            <div className="text-xs text-gray-500 mt-1">Bergabung {form.joinDate}</div>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-5 pt-7">
          <Field label="Nama Lengkap"><Input data-testid="profile-name" value={form.name} onChange={(e) => set("name", e.target.value)} /></Field>
          <Field label="Jabatan"><Input data-testid="profile-role" value={form.role} onChange={(e) => set("role", e.target.value)} /></Field>
          <Field label="Email"><Input data-testid="profile-email" value={form.email} onChange={(e) => set("email", e.target.value)} /></Field>
          <Field label="Telepon"><Input data-testid="profile-phone" value={form.phone} onChange={(e) => set("phone", e.target.value)} /></Field>
          <Field label="Cabang"><Input data-testid="profile-branch" value={form.branch} onChange={(e) => set("branch", e.target.value)} /></Field>
          <Field label="Tanggal Bergabung"><Input data-testid="profile-joindate" value={form.joinDate} onChange={(e) => set("joinDate", e.target.value)} /></Field>
        </div>

        <div className="mt-7 flex items-center justify-between">
          <Button variant="outline" onClick={handleLogout} data-testid="profile-logout" className="h-11 px-5 text-red-500 border-red-200 hover:bg-red-50 hover:text-red-600">
            <LogOut className="w-4 h-4 mr-2" /> Keluar
          </Button>
          <Button onClick={handleSave} data-testid="save-profile-btn" className="mpl-btn-primary h-11 px-6">
            <Save className="w-4 h-4 mr-2" /> Simpan Perubahan
          </Button>
        </div>
      </div>
    </div>
  );
}

function Field({ label, children }) {
  return (
    <div>
      <Label className="text-[10px] tracking-wider uppercase text-gray-500 font-semibold">{label}</Label>
      <div className="mt-1.5">{children}</div>
    </div>
  );
}
